userStories.agentControllerScript:
// -- 1. UseCase speichern ----------------------
agentController.addUseCase('stage_main', {
  title: 'Button bewegt sich bei Maus-Eintritt',
  description: 'Ein Button soll bei jedem onMouseEnter-Event an eine zufaellige Position auf der Stage springen.',
  priority: 'medium',
  compType: 'TButton', compName: 'MovingButton',
  eventName: 'onMouseEnter',
  taskName: 'MoveButtonTask',
  agentHints: 'Nutze Math.random() im Bereich [0, stage.width - button.width].',
});

// -- 2. Task erstellen --------------------------
agentController.createTask('stage_main', 'MoveButtonTask', 'Button bewegt sich bei Maus-Eintritt');

// -- 3. Actions hinzufuegen ---------------------
agentController.addAction('MoveButtonTask', 'set_property', 'MoveButton', {
  target: 'MovingButton',
  changes: {
    left: 'random',
    top: 'random'
  }
});

// -- 4. Event verknuepfen -----------------------
agentController.connectEvent('stage_main', 'MovingButton', 'onMouseEnter', 'MoveButtonTask');

// -- 5. Flow generieren -------------------------
agentController.generateTaskFlow('MoveButtonTask');

// -- 6. Status auf 'in_progress' setzen ----------
// agentController.updateUseCaseStatus('<id>', 'in_progress');

// Hinweise: Nutze Math.random() im Bereich [0, stage.width - button.width].
